+                continue;
+            }
+            let Some(stem) = path.file_stem().and_then(|s| s.to_str()) else {
+                continue;
+            };
+            let Ok(segment_seq) = stem.parse::<u64>() else {
+                continue;
+            };
+            segment_files.push((segment_seq, path));
+        }
+        segment_files.sort_by_key(|(segment_seq, _)| *segment_seq);
+        Ok(segment_files)
+    }
